#!/usr/bin/env bash
# Iteration 4 — fuzzy hydration + grid/state/MW filters on semantic search.
# Replaces dchub_iteration_3_routes.py with v2.
set -e
cd ~/workspace

# Extract the corrected blueprint
echo '' | base64 -d | tar xzf -

echo "Replaced dchub_iteration_3_routes.py ($(wc -l < dchub_iteration_3_routes.py) lines)"

# Sanity check imports cleanly
python3 -c "
import sys; sys.path.insert(0, '.')
from dchub_iteration_3_routes import register_iteration_3_routes, semantic_search, list_grids, _apply_filters, _hydrate, GRID_TERRITORIES
print('LOCAL IMPORT OK')
print('Grids defined:', sorted(GRID_TERRITORIES.keys()))
"

# Commit + push
git add dchub_iteration_3_routes.py
git commit -m "feat(search): iteration 4 — fuzzy hydration + grid/state/MW filters

- _hydrate now uses three strategies in order; reports hydration_method:
  exact-name-provider -> fuzzy-name-ilike (paren-strip) -> coord-proximity
- semantic_search adds filter params: grid, states, provider, country,
  status, min_mw, max_mw. Over-fetches 5x topK from Vectorize when filters
  are present, applies them, trims to topK. Adds filter_stats to response.
- New /api/v1/search/grids exposes ISO->state-territory map for the UI.
- Adds 'features' field to /search/health so the frontend can introspect
  what's supported."
git push origin main

echo ""
echo "=========================================================="
echo "Wait ~90s for Railway, then verify with these:"
echo ""
echo "  # Health (now includes 'features' + 'grids' fields)"
echo "  curl -s 'https://dchub-backend-production.up.railway.app/api/v1/search/health' | python3 -m json.tool"
echo ""
echo "  # The PJM-aware query that returned Brazilian DCs before"
echo "  curl -s 'https://dchub-backend-production.up.railway.app/api/v1/search/semantic?q=hyperscale&grid=PJM&min_mw=30&topK=5&hydrate=true' | python3 -m json.tool | head -80"
echo ""
echo "  # Grid territories"
echo "  curl -s 'https://dchub-backend-production.up.railway.app/api/v1/search/grids' | python3 -m json.tool"
echo "=========================================================="
